select.if:
/* OpenMgmtMapper.selectOpenMgmtListExcel */ SELECT REQ.PROD_TYPE_NM AS prodTypeNm /*상품구분 */ , SUB.CONTRACT_NUM AS contractNum /*계약번호 */ , REQ.RES_NO AS resNo /*예약번호 */ , SUB.SUB_LINK_NAME AS cstmrName /*고객명 */ , SUB.USER_SSN AS ssn /*주민번호 */ , CASE WHEN REQ.CSTMR_TYPE = 'JP' OR REQ.CSTMR_TYPE = 'PP' THEN '' ELSE SUBSTR(REPLACE(CRYPTO_AES256.DEC_AES(SUB.USER_SSN), '-', ''), 0, 6) END birth , CASE WHEN REQ.CSTMR_TYPE = 'JP' OR REQ.CSTMR_TYPE = 'PP' THEN '' ELSE SUBSTR(REPLACE(CRYPTO_AES256.DEC_AES(SUB.USER_SSN), '-', ''), 7, 1) END gender , CASE WHEN REQ.CSTMR_TYPE = 'JP' OR REQ.CSTMR_TYPE = 'PP' THEN 0 ELSE FN_GET_AGE_JAVA(CRYPTO_AES256.DEC_AES(SUB.USER_SSN)) END age , REQ.REQ_BUY_TYPE_NM AS reqBuyTypeNm /*구매유형 */ , REQ.OPER_TYPE AS operType , REQ.OPER_TYPE_NM AS operTypeNm /*업무구분 */ , REQ.MOVE_COMPANY AS moveCompany , REQ.MOVE_COMPANY_NM AS moveCompanyNm /*이동전 통신사 */ , SUB.SUBSCRIBER_NO AS subscriberNo /*휴대폰번호 */ , REQ.FST_RATE_NM AS fstRateNm /*최초요금제 */ , REQ.LST_RATE_NM AS lstRateNm /*현재요금제 */ , REQ.SALE_PLCY_NM AS salePlcyNm /*판매정책 */ , TO_NUMBER(SUBSTR(REQ.INST_INFO, 26, 3)) AS enggMnthCnt /*약정개월수 */ , TO_NUMBER(SUBSTR(REQ.INST_INFO, 23, 3)) AS instMnthCnt /*할부개월수 */ , SUB.MODEL_NAME AS lstModelNm /*단말모델명 */ , SUB.INTM_SRL_NO AS lstModelSrlNum /*단말일련번호 */ , NVL(TRIM(SUBSTR(REQ.FST_MODEL_INFO, 21 , 30)), REQ.REQ_USIM_NAME) AS fstModelNm /*최초개통단말 */ , NVL(TRIM(SUBSTR(REQ.FST_MODEL_INFO, 51 , 30)), SUB.ICC_ID) AS fstModelSrlNum /*최초단말일련번호*/ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'MSP0003' AND CD_VAL = SUB.SUB_STATUS) AS subStatusNm /*상태 */ , CASE WHEN SUB.SUB_STATUS = 'C' THEN CASE WHEN TO_DATE(SUBSTR(SUB.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD') - TO_DATE(SUB.LST_COM_ACTV_DATE, 'YYYYMMDD') = 0 THEN '당일개통취소' WHEN TO_DATE(SUBSTR(SUB.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD') - TO_DATE(SUB.LST_COM_ACTV_DATE, 'YYYYMMDD') < 15 THEN '14일이내해지' WHEN TO_DATE(SUBSTR(SUB.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD') - TO_DATE(SUB.LST_COM_ACTV_DATE, 'YYYYMMDD') < 90 THEN '90일이내해지' ELSE '일반해지' END ELSE '' END AS canRsn /*해지사유*/ , FN_GET_CODENM('RCP0007', REQ.ON_OFF_TYPE) AS onOffTypeNm /*모집경로 */ , REQ.OPEN_MARKET_REFERER AS openMarketReferer /*유입경로 */ , REQ.RECOMMEND_FLAG_NM AS recommendFlagNm /*추천인구분 */ , REQ.RECOMMEND_INFO AS recommendInfo /*추천인정보 */ , REQ.REC_YN AS recYn /*녹취여부 */ , (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = SUB.OPEN_AGNT_CD) AS agentNm /*대리점 */ , REQ.SHOP_CD AS shopCd , REQ.SHOP_NM AS shopNm /*판매점 */ , TO_CHAR(TO_DATE(REQ.REQ_IN_DAY,'YYYY-MM-DD HH24:MI:SS'), 'YYYY-MM-DD HH24:MI:SS') AS reqInDay /*신청일자 */ , TO_CHAR(TO_DATE(SUB.LST_COM_ACTV_DATE, 'YYYYMMDD' ), 'YYYY-MM-DD') AS openDt /*개통일자 */ , TO_CHAR(TO_DATE(DECODE(SUB.SUB_STATUS,'C',SUBSTR(SUB.SUB_STATUS_DATE,1,8),''),'YYYYMMDD'),'YYYY-MM-DD') AS tmntDt /*해지일자*/ , REQ.MINOR_AGENT_NAME AS minorAgentName /*법정대리인 */ , REQ.MINOR_AGENT_REL_NM AS minorAgentRelation /*관계 */ , REQ.MINOR_AGENT_TEL AS minorAgentTel /*대리인연락처 */ , REQ.APP_NM AS appNm /*유해차단APP명 */ , REQ.JOIN_PAY_MTHD_NM AS joinPayMthdNm /*가입비납부방법 */ , REQ.JOIN_PRICE AS joinPrice /*가입비 */ , REQ.USIM_PAY_MTHD_NM AS usimPayMthdNm /*USIM납부방법 */ , REQ.USIM_PRICE AS usimPrice /*USIM비 */ , SUB.OPEN_AGNT_CD AS openAgntCd /*대리점ID */ , TO_NUMBER(SUBSTR(REQ.INST_INFO, 13, 10)) AS instOrginAmnt /*할부원금 */ , CASE WHEN SUBSTR(REQ.SIM_INFO, 36, 1) IN ('A', 'R') THEN (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0058' AND CD_VAL = SUBSTR(REQ.SIM_INFO, 1, 2)) ELSE (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0058' AND CD_VAL = SUBSTR(REQ.INST_INFO, 1, 2)) END AS sprtTpNm /*할인유형 */ , SUBSTR(REQ.INST_INFO, 29, 14) AS grntInsrMngmNo /*보증보험관리번호*/ , SUBSTR(REQ.INST_INFO, 43, 1) AS grntInsrStatCd , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'MSP0011' AND CD_VAL = SUBSTR(REQ.INST_INFO, 43, 1)) AS grntInsrStatNm /*보증보험가입상태*/ , TRIM(SUBSTR(REQ.SIM_INFO, 6, 14)) AS simId /*심플할인ID */ , TO_NUMBER(SUBSTR(REQ.SIM_INFO, 3, 3)) AS simEnggMnthCnt /*심플약정기간 */ , TO_CHAR(TO_DATE(SUBSTR(REQ.SIM_INFO, 20, 8), 'YYYYMMDD'), 'YYYY-MM-DD') AS simStartDt /*심플약정시작일자*/ , TO_CHAR(TO_DATE(SUBSTR(REQ.SIM_INFO, 28, 8), 'YYYYMMDD'), 'YYYY-MM-DD') AS simEndDt /*심플약정종료일자*/ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'MSP0010' AND CD_VAL = SUBSTR(REQ.SIM_INFO, 36, 1)) AS simStatNm /*심플약정상태 */ , REQ.RENTAL_BASE_AMT AS rentalBaseAmt /*렌탈기본료 */ , REQ.RENTAL_BASE_DC_AMT AS rentalBaseDcAmt /*렌탈료할인 */ , REQ.RENTAL_MODEL_CP_AMT AS rentalModelCpAmt /*렌탈단말배상금 */ , REQ.CSTMR_TYPE AS cstmrType /*고객구분 */ , REQ.DVC_CHG_CNT AS dvcChgCnt /*기변횟수*/ , SUBSTR(REQ.DVC_CHG_INFO, 1, 8) AS dvcChgDt /* 기변일자 */ , TRIM(SUBSTR(REQ.DVC_CHG_INFO, 9, 10)) AS dvcModelId /* 기변모델ID */ , TRIM(SUBSTR(REQ.DVC_CHG_INFO, 19, 30)) AS dvcModelNm /* 기변모델명 */ , TRIM(SUBSTR(REQ.DVC_CHG_INFO, 49, 20)) AS dvcIntmSrlNo /* 기변일련번호 */ , (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = TRIM(SUBSTR(REQ.DVC_CHG_INFO, 69, 10))) AS dvcAgntNm /* 기변대리점 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0049' AND CD_VAL = SUBSTR(REQ.DVC_CHG_INFO, 79, 4)) AS dvcOperTypeNm /* 기변유형명 */ , TO_NUMBER(SUBSTR(REQ.DVC_CHG_INFO, 83, 10)) AS dvcHndstAmnt /* 기변단말출고가 */ , TO_NUMBER(SUBSTR(REQ.DVC_CHG_INFO, 93, 10)) AS dvcInstOrginAmnt /* 기변단말할부원금 */ , TO_NUMBER(SUBSTR(REQ.DVC_CHG_INFO, 103, 3)) AS dvcInstMnthCnt /* 기변단말할부개월수 */ , TO_NUMBER(SUBSTR(REQ.DVC_CHG_INFO, 106, 3)) AS dvcEnggMnthCnt /* 기변약정개월수 */ , SUBSTR(REQ.DVC_CHG_INFO, 109) AS dvcSalePlcyNm /* 기변판매정책 */ , REQ.OTA_DATE AS otaDate /* OTA등록일자 */ , DECODE(SUB.SUB_STATUS, 'C' ,'', REQ.CATCH_CALL) AS catchcall /* 캐치콜가입일자*/ , REQ.CATCH_CALL_CAN AS catchcallCan /* 캐치콜해지일자*/ , TO_CHAR(TO_DATE(DECODE(SUB.SUB_STATUS,'S',SUBSTR(SUB.SUB_STATUS_DATE,1,8),''),'YYYYMMDD'),'YYYY-MM-DD') AS stopDt /*정지일자*/ , P.PROMOTION_NM AS promotionnm /* 프로모션명 */ , P.STRT_DT AS prmtstrtdt /* 프로모션시작일 */ , P.END_DT AS prmtenddt /* 프로모션종료일 */ , P.BENEFIT_01 AS benefit01 /* 혜택_추가데이터제공여부(Y/N) */ , P.BENEFIT_02 AS benefit02 /* 혜택_추가기본료할인여부(Y/N) */ , P.BENEFIT_03 AS benefit03 /* 혜택_가입비면제여부(Y/N) */ , P.BENEFIT_04 AS benefit04 /* 혜택_유심비면제여부(Y/N) */ , REQ.REAL_SHOP_NM AS realShopNm /* 실 판매점 */ FROM MSP_JUO_SUB_INFO SUB , MSP_REQUEST_DTL REQ ,MSP_PROMOTION_MST P
, ( SELECT CONTRACT_NUM FROM MSP_JUO_MODEL_INFO WHERE INTM_SRL_NO = #{searchName} GROUP BY CONTRACT_NUM ) MDL
WHERE SUB.PPPO = 'PO' AND SUB.CONTRACT_NUM = REQ.CONTRACT_NUM AND REQ.PROMOTION_CD = P.PROMOTION_CD(+)
AND SUB.LST_COM_ACTV_DATE BETWEEN #{lstComActvDateF} AND #{lstComActvDateT}
AND SUB.SUB_STATUS = #{subStatus}
AND SUB.OPEN_AGNT_CD = #{cntpntShopId}
AND REQ.SHOP_CD = #{pAgentCode}
AND REQ.REQ_BUY_TYPE = #{reqBuyTypeS}
AND REQ.ON_OFF_TYPE = #{onOffType}
AND REQ.CSTMR_TYPE = 'NM'
AND REQ.APP_BLCK_AGRM_YN = 'Y'
AND REQ.APP_INST_YN = 'Y'
AND SUB.SUB_LINK_NAME LIKE '%' || #{searchName} || '%'
AND (SUB.CONTRACT_NUM = #{searchName} OR SUB.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND SUB.SUBSCRIBER_NO = #{searchName}
AND SUB.CONTRACT_NUM = MDL.CONTRACT_NUM
AND REQ.REQUEST_KEY IS NULL
AND EXISTS ( SELECT 1 FROM LGS_TELECOM_IF WHERE SVC_CT_NUM = SUB.CONTRACT_NUM AND LGS_PRCS_YN = 'Y' AND PRDT_TYPE_CD = 'D1' AND TO_DATE(SUBSTR(SVC_OPEN_DTTM, 1, 8), 'YYYYMMDD') - TO_DATE(SUB.LST_COM_ACTV_DATE, 'YYYYMMDD') < 15 ) AND EXISTS ( SELECT 1 FROM MSP_JUO_MODEL_INFO WHERE CONTRACT_NUM = SUB.CONTRACT_NUM AND MODEL_TYPE = 'D1' AND EVNT_CD = 'C07' )
AND EXISTS ( SELECT 1 FROM MSP_JUO_ADD_INFO WHERE CONTRACT_NUM = SUB.CONTRACT_NUM AND SIM_ID IS NOT NULL )
AND EXISTS ( SELECT 1 FROM MSP_JUO_ADD_INFO WHERE CONTRACT_NUM = SUB.CONTRACT_NUM AND BL_DC_TYPE = #{sprtTp} )
AND NVL(REQ.PROD_TYPE, '01') = #{prodType}
AND ( REQ.OPER_TYPE = #{operType} OR EXISTS ( SELECT 1 FROM MSP_DVC_CHG_AGNT_HST X, MSP_REQUEST Y WHERE X.REQUEST_KEY = Y.REQUEST_KEY AND X.CONTRACT_NUM = SUB.CONTRACT_NUM AND TO_DATE(SUBSTR(APPL_END_DTTM, 1, 8), 'YYYYMMDD') - TO_DATE(SUBSTR(APPL_STRT_DTTM, 1, 8), 'YYYYMMDD') > 14 AND Y.OPER_TYPE = #{operType} AND SUBSTR(X.APPL_STRT_DTTM, 1, 8) BETWEEN #{lstComActvDateF} AND #{lstComActvDateT} ) )
ORDER BY SUB.LST_COM_ACTV_DATE DESC
